function clean(value) { return String(value || '').trim(); }
function n(value) { const num = Number(value || 0); return Number.isFinite(num) ? num : 0; }
function arr(value) { return Array.isArray(value) ? value : []; }
function safe(fn, fallback) { try { return fn(); } catch { return fallback; } }
function button(menu, text, action, extra = {}) { return menu.button(text, action, extra); }
function linkButton(menu, text, url) { return (menu.link ? menu.link(text, url) : { type: 'link', text, url }); }
function keyboard(menu, rows) { return menu.keyboard(rows); }
function footer(menu) { return [[button(menu, '📊 В начало статистики', 'admin_section_stats')], [button(menu, '🏠 Главное меню', 'admin_section_main')]]; }
function adFooter(menu) { return [[button(menu, '📣 В начало рекламы', 'admin_stats_campaigns')], [button(menu, '🏠 Главное меню', 'admin_section_main')]]; }
function screen(menu, id, title, lines, rows) { return { id, text: [title, '', ...(lines || [])].filter(Boolean).join('\n'), attachments: keyboard(menu, rows || footer(menu)) }; }
function fmt(value, fallback = 'нет данных') { return value === null || value === undefined || value === '' ? fallback : String(value); }
function delta(value) { if (value === null || value === undefined) return 'нужен второй снимок'; const num = n(value); return num > 0 ? `+${num}` : String(num); }
function postByKey(commentKey) { return safe(() => store.getPost(clean(commentKey)), null); }
function postTitle(post = {}) { return stats.short(clean(post.originalText || post.postText || post.text || post.caption || 'Пост без текста'), 90); }
function channelTitle(post = {}) { const explicit = clean(post.channelTitle || post.channelName || post.chatTitle || post.name); if (explicit && !/^-?\d{6,}$/.test(explicit)) return explicit; const channel = safe(() => arr(store.getChannelsList()).find((item) => clean(item.channelId) === clean(post.channelId)), null); return clean(channel && (channel.title || channel.channelTitle || channel.name)) || 'Канал без названия'; }
function snap(ctx = {}) { return stats.buildMonitoringSnapshot({ userId: ctx.userId || '' }); }
function eventName(event = {}) { return stats.displayEventName ? stats.displayEventName(event) : clean(event.displayName || event.username || [event.firstName, event.lastName].filter(Boolean).join(' ') || event.userId || 'Пользователь'); }
function eventSource(event = {}) { const src = clean(event.attribution && event.attribution.source); return src && src !== 'Источник неизвестен' ? src : 'источник неизвестен'; }
function eventLine(event = {}, index = 0) { return `${index + 1}. ${eventName(event)} · ${eventSource(event)}`; }
function userChannels(ctx = {}) { const posts = arr(store.getPostsList()); const ids = new Set(posts.map((p) => clean(p.channelId)).filter(Boolean)); const list = arr(store.getChannelsList()).filter((c) => ids.has(clean(c.channelId)) || clean(c.channelId)); const seen = new Set(); return list.filter((c) => { const id = clean(c.channelId); if (!id || seen.has(id)) return false; seen.add(id); return true; }).slice(0, 12); }
function channelHumanName(ch = {}) { return adCampaigns.channelTitle ? adCampaigns.channelTitle(ch) : channelTitle(ch); }
function channelById(channelId = '', ctx = {}) { return userChannels(ctx).find((x) => clean(x.channelId) === clean(channelId)) || store.getChannelsList().find((x) => clean(x.channelId) === clean(channelId)) || { channelId }; }
function directUrlForChannel(channelId = '', ctx = {}) { return adCampaigns.targetUrlForChannel(channelById(channelId, ctx)); }
function hasDirectUrl(value = '') { return Boolean(adCampaigns.normalizeDirectUrl ? adCampaigns.normalizeDirectUrl(value) : /^https?:\/\//i.test(clean(value))); }
function externalChannelId(url = '') { return `external_${adCampaigns.slugify ? adCampaigns.slugify(url).slice(0, 42) : Date.now().toString(36)}`; }
function adListOptions(ctx = {}) { return { userId: clean(ctx.userId) }; }
function safeAdText(value = '', fallback = 'не указано') { const text = clean(value).replace(/\s+/g, ' '); if (!text) return fallback; if (/\b(postId|channelId|commentKey|token|payload|trace)\b/i.test(text)) return fallback; if (/^-?\d{6,}$/.test(text) || /^ad_[a-z0-9_:-]+$/i.test(text)) return fallback; return stats.short(text, 80); }
function adCardPayload(c = {}) { return { campaignId: c.id, slug: c.slug, source: 'ad_link_card' }; }

function campaignRows(menu, ctx = {}) { const campaigns = adCampaigns.listCampaigns('', adListOptions(ctx)).slice(0, 6); const rows = campaigns.map((c, i) => [button(menu, `${i + 1}. ${safeAdText(c.name, 'Рекламная ссылка')}`, 'admin_stats_campaign_view', { campaignId: c.id, slug: c.slug })]); if (!rows.length) rows.push([button(menu, '➕ Создать первую ссылку', 'admin_stats_campaign_create')]); else rows.unshift([button(menu, '➕ Создать ссылку', 'admin_stats_campaign_create')]); rows.push([button(menu, '🧭 Источники', 'admin_stats_sources_cache')], ...adFooter(menu)); return rows; }
function homeRows(menu) { return [[button(menu, '📈 Рост', 'admin_stats_growth')], [button(menu, '🎯 Источники', 'admin_stats_sources')], [button(menu, '🧭 Воронка', 'admin_stats_funnel')], [button(menu, '📝 Контент', 'admin_stats_content')], [button(menu, '📤 Отчёт и качество данных', 'admin_stats_quality')], [button(menu, '🏠 Главное меню', 'admin_section_main')]]; }


function pr226Dataset(ctx = {}, payload = {}) { return statsPr226.loadStatsDataset(statsPr226.resolveStatsContext(ctx, payload), payload); }
function freshnessLine(d) { return d.freshness || 'Нет свежих данных.'; }
function pr226HomeScreen(menu, ctx = {}) { const d = pr226Dataset(ctx, {}); return screen(menu, 'stats_product_perfect_home_pr226', '📊 Статистика', ['Рост, источники, воронка, контент и качество данных.', freshnessLine(d)], homeRows(menu)); }
