async function handleTextInput(menu, ctx = {}) { const userId = clean(ctx.userId); const text = clean(ctx.text); const state = store.getSetupState(userId) || {}; const manual = state.statsManualCostFlow || null; if (manual && clean(state.activeAdminFlowKind) === 'stats_manual_cost') { if (manual.step === 'source') { const parts = text.split('/').map(x=>clean(x)); store.setSetupState(userId, { statsManualCostFlow: { ...manual, step:'amount', source:parts[0]||text, campaign:parts[1]||'' }, activeAdminFlowKind:'stats_manual_cost' }); return screen(menu, 'stats_manual_cost_amount_pr226', 'Расходы вручную', ['Теперь напишите сумму. Валюта по умолчанию RUB.', `Источник: ${parts[0]||text}`, `Кампания: ${parts[1]||'не указана'}`], [[button(menu,'❌ Отменить','admin_stats_manual_cost_cancel')], ...footer(menu)]); } if (manual.step === 'amount') { const amount = Number(String(text).replace(',', '.')); if (!Number.isFinite(amount) || amount <= 0) return screen(menu, 'stats_manual_cost_bad_amount_pr226', 'Расходы вручную', ['Сумма должна быть больше нуля. Напишите сумму числом.'], [[button(menu,'❌ Отменить','admin_stats_manual_cost_cancel')], ...footer(menu)]); const saved = statsPr226.writeManualCost({ ...ctx, tenantKey: manual.tenantKey, ownerUserId: manual.ownerUserId, targetKind: manual.targetKind, targetId: manual.targetId, channelId: manual.channelId, chatId: manual.chatId }, { source: manual.source, campaign: manual.campaign, amount, currency:'RUB' }, 'added'); const readBack = statsPr226.getManualCosts({ ...ctx, tenantKey: manual.tenantKey, ownerUserId: manual.ownerUserId, targetKind: manual.targetKind, targetId: manual.targetId, channelId: manual.channelId, chatId: manual.chatId }, { source: manual.source, campaign: manual.campaign, period:'all' }).find(x=>x.costId===saved.costId); store.setSetupState(userId, { statsManualCostFlow:null, activeAdminFlowKind:'' }); return screen(menu, 'stats_manual_cost_saved_pr226', 'Расходы вручную', [readBack ? 'Расход сохранён и проверен чтением.' : 'Расход не подтверждён чтением. Попробуйте позже.', `Источник: ${manual.source}`, `Сумма: ${amount} RUB`], [[button(menu,'🎯 Источники','admin_stats_sources',{targetKind:manual.targetKind,targetId:manual.targetId,channelId:manual.channelId,chatId:manual.chatId})], [button(menu,'Удалить расход','admin_stats_manual_cost_delete',{costId:saved.costId,source:manual.source,campaign:manual.campaign,targetKind:manual.targetKind,targetId:manual.targetId,channelId:manual.channelId,chatId:manual.chatId})], ...footer(menu)]); } } const flow = state.statsCampaignFlow || null; if (!flow || clean(state.activeAdminFlowKind) !== 'stats_campaign') return null; if (!text) return screen(menu, 'stats_campaign_empty_text', '📣 Создание рекламной ссылки', ['Пришлите текстом значение для текущего шага.'], [[button(menu, '❌ Отменить', 'admin_stats_campaign_cancel')], ...adFooter(menu)]); if (flow.step === 'external_channel_url') { if (!hasDirectUrl(text)) return screen(menu, 'stats_campaign_bad_channel_url', '📣 Другой канал', ['Ссылка должна быть прямой ссылкой на MAX-канал.', 'Например: https://max.ru/your_channel'], [[button(menu, '❌ Отменить', 'admin_stats_campaign_cancel')], ...adFooter(menu)]); const direct = adCampaigns.normalizeDirectUrl ? adCampaigns.normalizeDirectUrl(text) : text; store.setSetupState(userId, { statsCampaignFlow: { ...flow, step: 'name', channelId: externalChannelId(direct), targetUrl: direct, channelTitle: 'Другой канал' } }); return screen(menu, 'stats_campaign_name', '📣 Создание рекламной ссылки', ['Канал: другой канал', 'Ссылка сохранена.', '', 'Теперь напишите название кампании.'], [[button(menu, '❌ Отменить', 'admin_stats_campaign_cancel')], ...adFooter(menu)]); } if (flow.step === 'name') { store.setSetupState(userId, { statsCampaignFlow: { ...flow, step: 'source', name: text } }); return screen(menu, 'stats_campaign_source', '📣 Создание рекламной ссылки', [`Кампания: ${stats.short(text, 80)}`, '', 'Теперь напишите источник / площадку.', 'Например: блогер Маша, TG-канал, VK, MAX, сторис.'], [[button(menu, '❌ Отменить', 'admin_stats_campaign_cancel')], ...adFooter(menu)]); } if (flow.step === 'source') { const campaign = adCampaigns.createCampaign({ channelId: flow.channelId, name: flow.name, source: text, targetUrl: flow.targetUrl || directUrlForChannel(flow.channelId, ctx), channelTitleOverride: flow.channelTitle || '', createdByUserId: userId, config: ctx.config || {} }); const proof = createCanonicalTrackingLinkForCampaign(campaign, { ...ctx, ownerUserId: ctx.ownerUserId || userId }); campaign.statsLinkVerified = proof.ok; campaign.statsLinkId = proof.link && proof.link.linkId; campaign.statsProof = proof; store.setSetupState(userId, { statsCampaignFlow: null, activeAdminFlowKind: '' }); return campaignCreatedScreen(menu, campaign, ctx); } return null; }

