async function gifts(menu, ctx = {}) { const s = snap(ctx); const conversion = stats.pct(s.counts.giftClaims, s.counts.clicks || s.counts.gifts); return screen(menu, 'stats_monitoring_gifts', '🎁 Подарки', [`Подарков создано: ${s.counts.gifts}`, `Получений подарка: ${s.counts.giftClaims}`, `Клики кнопок/рекламы: ${s.counts.clicks}`, `Конверсия: ${conversion}`, '', 'Подарки используем и как лид-магнит, и как точку атрибуции рекламы.'], [[button(menu, '🧭 Источники', 'admin_stats_sources_cache')], ...footer(menu)]); }
async function buttonsCache(menu, ctx = {}) { const s = snap(ctx); const top = new Map(); s.clicks.forEach((click) => { const key = clean(click.buttonText || click.campaign || click.buttonId || 'Кнопка'); const item = top.get(key) || { key, count: 0 }; item.count += 1; top.set(key, item); }); const lines = [`Кнопок под постами: ${s.counts.buttons}`, `Кликов кнопок/рекламы: ${s.counts.clicks}`, `За 24 часа: ${s.counts.clicks24h}`, `Уникальных кликеров: ${s.counts.clickers}`, '', 'Топ ссылок/кнопок:']; Array.from(top.values()).sort((a, b) => b.count - a.count).slice(0, 5).forEach((item, i) => lines.push(`${i + 1}. ${stats.short(item.key, 42)} · ${item.count}`)); if (!top.size) lines.push('Пока нет кликов.'); return screen(menu, 'stats_monitoring_buttons', '🔘 Кнопки под постами', lines, [[button(menu, '📣 Реклама / источники', 'admin_stats_campaigns')], ...footer(menu)]); }
async function postStats(menu, payload, ctx = {}) { const key = clean(payload.commentKey || payload.key || ''); if (!key) return screen(menu, 'stats_post_picker', '📌 Статистика поста', ['Сначала выберите канал, затем пост.', '', 'Так посты разных каналов не смешиваются.'], [[button(menu, '📺 Выбрать канал и пост', 'comments_select_post', { source: 'stats' })], ...footer(menu)]); const analytics = safe(() => growthService.buildPostAnalytics(key), null); const post = postByKey(key) || {}; if (!analytics) return screen(menu, 'stats_post_not_found', '📌 Статистика поста', ['Пост не найден. Выберите другой пост.'], [[button(menu, '📺 Выбрать другой пост', 'comments_select_post', { source: 'stats' })], ...footer(menu)]); const t = analytics.totals || {}; return screen(menu, 'stats_post_detail', '📌 Статистика поста', [`Канал: ${channelTitle(post)}`, `Пост: ${postTitle(post)}`, '', `Комментарии: ${n(t.comments)}`, `Участники: ${n(t.participants)}`, `Ответы: ${n(t.replies)}`, `Реакции: ${n(t.reactions)}`, `Кнопки/реклама: ${n(t.clicks)}`, `Голоса в опросах: ${n(t.pollVotes)}`, `Подарки: ${n(analytics.gifts)}`], [[button(menu, '📺 Выбрать другой пост', 'comments_select_post', { source: 'stats' })], [button(menu, '📊 Обзор', 'admin_stats_overview_cache')], ...footer(menu)]); }
let refreshState = { status: 'idle', startedAt: 0, finishedAt: 0, ok: 0, errors: 0, channels: 0, joined: 0, left: 0, lastError: '' };
async function runRefresh(ctx = {}) { const s = snap(ctx); refreshState = { status: 'running', startedAt: Date.now(), finishedAt: 0, ok: 0, errors: 0, channels: s.channelIds.length, joined: 0, left: 0, lastError: '' }; for (const channelId of s.channelIds.slice(0, 12)) { try { const result = await growthService.captureChannelAudienceSnapshot({ channelId, config: ctx.config || {}, includeMembers: true }); refreshState.ok += 1; refreshState.joined += arr(result && result.joined).length; refreshState.left += arr(result && result.left).length; } catch (error) { refreshState.errors += 1; refreshState.lastError = clean(error && error.message || error).slice(0, 180); } } refreshState.status = 'done'; refreshState.finishedAt = Date.now(); }
function asyncSafe(fn) { setImmediate(() => Promise.resolve().then(fn).catch(() => {})); }
async function refresh(menu, ctx = {}) { const s = snap(ctx); if (!s.channelIds.length) return screen(menu, 'stats_refresh_no_channels', '🔄 Обновить данные', ['Каналы не найдены. Сначала подключите канал.'], [[button(menu, '📺 Подключение канала', 'admin_section_channels')], ...footer(menu)]); asyncSafe(() => runRefresh(ctx)); return screen(menu, 'stats_refresh_started', '🔄 Обновить данные', [`Обновление запущено.`, `Каналов в очереди: ${s.channelIds.length}`, '', 'Бот снимет текущий список подписчиков и сохранит профили. Следующие снимки покажут, кто пришёл и кто ушёл.'], [[button(menu, '🔄 Проверить результат', 'admin_stats_refresh_status')], ...footer(menu)]); }
async function refreshStatus(menu) { const s = refreshState || {}; return screen(menu, 'stats_refresh_status', '🔄 Статус обновления', [`Статус: ${s.status || 'idle'}`, `Каналов: ${n(s.channels)}`, `Успешно: ${n(s.ok)}`, `Ошибок: ${n(s.errors)}`, `Новых подписчиков: ${n(s.joined)}`, `Ушли: ${n(s.left)}`, s.startedAt ? `Старт: ${stats.ruTime(s.startedAt)}` : '', s.finishedAt ? `Финиш: ${stats.ruTime(s.finishedAt)}` : '', s.lastError ? `Последняя ошибка: ${s.lastError}` : ''].filter(Boolean), [[button(menu, '👥 Подписчики', 'admin_stats_subscribers_trend')], [button(menu, '📊 Обзор', 'admin_stats_overview_cache')], [button(menu, '🔄 Запустить ещё раз', 'admin_stats_refresh')], ...footer(menu)]); }
async function screenForPayloadLegacy(menu, payload = {}, ctx = {}) { const action = clean(payload.action); if (action === 'admin_section_stats') return pr226Home(menu, ctx); if (action === 'admin_stats_growth' || action === 'admin_stats_subscribers_day' || action === 'admin_stats_subscribers_trend') return pr226Growth(menu, payload, ctx); if (action === 'admin_stats_sources' || action === 'admin_stats_sources_cache') return pr226Sources(menu, payload, ctx); if (action === 'admin_stats_funnel' || action === 'admin_stats_buttons_cache') return pr226Funnel(menu, payload, ctx); if (action === 'admin_stats_content' || action === 'admin_stats_content_low' || action === 'admin_stats_posts_cache' || action === 'admin_stats_post_views' || action === 'admin_stats_comments_cache' || action === 'admin_stats_gifts_cache' || action === 'admin_stats_reactions_cache' || action === 'admin_stats_polls_cache') return pr226Content(menu, payload, ctx); if (action === 'admin_stats_quality') return pr226Quality(menu, payload, ctx); if (action === 'admin_stats_export') return pr226Export(menu, payload, ctx); if (action === 'admin_stats_post') return pr226PostStats(menu, payload, ctx); if (action === 'admin_stats_manual_costs' || action === 'admin_stats_manual_cost_source') return pr226ManualCosts(menu, payload, ctx); if (action === 'admin_stats_manual_cost_cancel') return pr226ManualCostCancel(menu, ctx); if (action === 'admin_stats_manual_cost_delete') return pr226ManualCostDelete(menu, payload, ctx); if (action === 'admin_stats_campaigns') return campaigns(menu, ctx); if (action === 'admin_stats_campaign_create') return campaignCreate(menu, ctx); if (action === 'admin_stats_campaign_external') return campaignExternal(menu, ctx); if (action === 'admin_stats_campaign_channel') return campaignChannel(menu, payload, ctx); if (action === 'admin_stats_campaign_cancel') return campaignCancel(menu, ctx); if (action === 'admin_stats_campaign_view') return campaignView(menu, payload, ctx); if (action === 'admin_stats_campaign_disable') return campaignDisable(menu, payload, ctx); if (action === 'admin_stats_refresh') return refresh(menu, ctx); if (action === 'admin_stats_refresh_status') return refreshStatus(menu, ctx); return null; }
// PR229 stats scope selector, channel/chat split and buttons cleanup.
const statsTargetsService = require('./services/statsTargetsService');
const PR229_RUNTIME = 'CC8.3.68-PR229-STATS-SCOPE-BUTTONS-CLEANUP';
function pr229Payload(extra={}){return {targetKind:extra.targetKind,targetId:extra.targetId,channelId:extra.channelId,chatId:extra.chatId};}
function scopeFromPayload(payload={},ctx={}){const kind=clean(payload.targetKind||ctx.targetKind); const targetId=clean(payload.targetId||ctx.targetId); const channelId=clean(payload.channelId||ctx.channelId); const chatId=clean(payload.chatId||ctx.chatId); return {targetKind:kind|| (chatId?'chat':(channelId?'channel':'all_channels')), targetId:targetId||chatId||channelId, channelId, chatId};}
function scopeLine(scope={},ctx={}){const targets=statsTargetsService.listStatsTargetsForUser(ctx.userId,ctx.config||{}); if(scope.targetKind==='all_channels') return 'Каналы: все подключённые каналы'; if(scope.targetKind==='all_chats') return 'Чаты: все подключённые чаты'; if(scope.targetKind==='chat'){const t=targets.chats.find(x=>x.chatId===scope.chatId||x.targetId===scope.targetId)||{}; return `Чат: ${t.title||'Чат без названия'}`;} const t=targets.channels.find(x=>x.channelId===scope.channelId||x.targetId===scope.targetId)||{}; return `Канал: ${t.title||'Канал без названия'}`;}
function scoped(menu,text,action,scope,extra={}){return button(menu,text,action,{...pr229Payload(scope),...extra});}
function pr229Footer(menu,scope){return [[scoped(menu,'📺 Сменить канал/чат','admin_section_stats',scope,{change:'1'})],[button(menu,'🏠 Главное меню','admin_section_main')]];}
function pr229Screen(menu,id,title,lines,rows){return screen(menu,id,title,lines,rows);}
async function pr229Root(menu,ctx={}){const explicit=scopeFromPayload(ctx,ctx); const explicitKind=clean(ctx.targetKind); if(clean(explicit.channelId||explicit.chatId)||['all_channels','all_chats'].includes(explicitKind))return pr229Home(menu,explicit,{...ctx,pr229LegacyNoChangeButton:true}); const r=statsTargetsService.listStatsTargetsForUser(ctx.userId,ctx.config||{}); if(!r.targets.length)return pr229Screen(menu,'stats_scope_empty_pr229','📊 Статистика',['Сначала подключите канал или чат, чтобы АдминКИТ мог показать статистику.'],[[button(menu,'📺 Подключить канал/чат','admin_section_channels')],[button(menu,'🏠 Главное меню','admin_section_main')]]); if(r.targets.length===1)return pr229Home(menu,pr229Payload(r.targets[0]),ctx); const rows=[]; r.channels.forEach(t=>rows.push([scoped(menu,`📺 ${t.title}`,'admin_stats_scope_select',t)])); r.chats.forEach(t=>rows.push([scoped(menu,`💬 ${t.title}`,'admin_stats_scope_select',t)])); if(r.channels.length>1)rows.push([scoped(menu,'📺 Все каналы','admin_stats_scope_select',{targetKind:'all_channels',targetId:'all_channels'})]); if(r.chats.length>1)rows.push([scoped(menu,'💬 Все чаты','admin_stats_scope_select',{targetKind:'all_chats',targetId:'all_chats'})]); rows.push([button(menu,'🏠 Главное меню','admin_section_main')]); return pr229Screen(menu,'stats_scope_selector_pr229','📊 Статистика',['Выберите, по какому объекту показать статистику.'],rows);}
