async function pr229Growth(menu,payload={},ctx={}){const scope=scopeFromPayload(payload,ctx); const d=statsPr226.loadStatsDataset({...ctx,...scope},payload); const g=d.growth; const audience=scope.targetKind==='chat'||scope.targetKind==='all_chats'?'Текущее количество участников: недоступно через текущий MAX API':'Текущее количество подписчиков: недоступно через текущий MAX API'; const lines=[scopeLine(scope,ctx),`Период: ${d.context.period}`,audience,`Пришло: +${g.joined}`,`Ушло: −${g.left}`,`С меткой: ${g.attributed}`,`Без метки: ${g.unattributed}`,'','По источникам:',...(g.bySource.length?g.bySource:[{source:'Без метки',count:0}]).map(x=>`— ${x.source}: ${x.count}`),freshnessLine(d)]; return pr229Screen(menu,'stats_growth_pr229','📈 Рост',lines,[[scoped(menu,'Сегодня','admin_stats_growth',scope,{period:'today'})],[scoped(menu,'7 дней','admin_stats_growth',scope,{period:'7d'}),scoped(menu,'30 дней','admin_stats_growth',scope,{period:'30d'})],...pr229Footer(menu,scope)]);}
async function pr229Sources(menu,payload={},ctx={}){const scope=scopeFromPayload(payload,ctx); const d=statsPr226.loadStatsDataset({...ctx,...scope},payload); const s=d.sources; return pr229Screen(menu,'stats_sources_pr229','🎯 Источники',[scopeLine(scope,ctx),`Клики: ${s.clicks}`,`Присоединились по источникам: ${s.attributedJoins}`,`Действия после входа: ${s.actionsAfterJoin}`,`Расходы вручную: ${s.noCosts?'не внесены':s.manualCosts.map(c=>`${c.source||'источник'}: ${c.amount} ${c.currency}`).join(', ')}`,s.noCosts?'CPA не показываем без расходов и вступлений. CPA появится, когда будут расходы и вступления по источнику.':`CPA: ${s.costTotal || 0} / ${s.attributedJoins || 0}`,freshnessLine(d)],[[scoped(menu,'Результаты по источникам','admin_stats_sources_results',scope)],[scoped(menu,'Расходы вручную','admin_stats_manual_costs',scope)],[button(menu,'📣 Перейти в раздел “Рекламные ссылки”','ad_links:home')],...pr229Footer(menu,scope)]);}
async function pr229Funnel(menu,payload={},ctx={}){const scope=scopeFromPayload(payload,ctx); const d=statsPr226.loadStatsDataset({...ctx,...scope},payload); const f=d.funnel; return pr229Screen(menu,'stats_funnel_pr229','🧭 Воронка',[scopeLine(scope,ctx),'tracking click → joined → action',`Клик: ${f.clicks}`,`Вступление: ${f.joined}`,`Действие: ${f.actions}`,`Точно: ${f.exact}`,`Вероятно: ${f.probable}`,`Недоступно: ${f.unavailable}`,freshnessLine(d)],pr229Footer(menu,scope));}
async function pr229Content(menu,payload={},ctx={}){const scope=scopeFromPayload(payload,ctx); const isChat=scope.targetKind==='chat'||scope.targetKind==='all_chats'; const d=statsPr226.loadStatsDataset({...ctx,...scope},payload); const lines=[scopeLine(scope,ctx)]; let rows=[]; if(isChat){lines.push('Активность чата: события входа/выхода, клики и действия, которые видит АдминКИТ.','Post metrics недоступны для чатов через текущий MAX API.',`Комментарии: ${d.content.comments}`,`CTA: ${d.content.ctaClicks}`,`Подарки: заявки ${d.content.giftRequests}, выдачи ${d.content.giftClaims}`,freshnessLine(d)); rows=pr229Footer(menu,scope);} else {lines.push(`Комментарии: ${d.content.comments}`,`CTA: ${d.content.ctaClicks}`,`Подарки: заявки ${d.content.giftRequests}, выдачи ${d.content.giftClaims}`,`Наблюдаемые репосты: ${d.content.observedForwards}`,'Просмотры недоступны через текущий MAX API, если нет снимка выбранного поста.',freshnessLine(d)); rows=[[scoped(menu,'Лучшие посты','admin_stats_content_top',scope)],[scoped(menu,'Посты с низкой активностью','admin_stats_content_low',scope)],[scoped(menu,'Статистика выбранного поста','admin_stats_post',scope,{postId:clean(payload.postId||ctx.postId),commentKey:clean(payload.commentKey||ctx.commentKey)})],...pr229Footer(menu,scope)];} return pr229Screen(menu,isChat?'stats_activity_pr229':'stats_content_pr229',isChat?'💬 Активность':'📝 Контент',lines,rows);}
async function pr229Quality(menu,payload={},ctx={}){const scope=scopeFromPayload(payload,ctx); return pr229Screen(menu,'stats_quality_pr229','📤 Отчёт и качество данных',[scopeLine(scope,ctx),'Данные разделены по выбранному объекту статистики и не смешиваются между каналами и чатами.','MAX API: текущая аудитория и post metrics показываются только когда они реально доступны.','Точно: события с tenant/scope.','Вероятно: атрибуция по источникам.','Снимки: post snapshots, если доступны.','Недоступно: метрики, которых нет в текущем MAX API.','Нет свежих данных'],[[scoped(menu,'Экспорт','admin_stats_export',scope)],[scoped(menu,'Свежесть','admin_stats_freshness',scope)],[scoped(menu,'Что считается точно','admin_stats_quality_exact',scope)],[scoped(menu,'Что считается вероятно','admin_stats_quality_probable',scope)],[scoped(menu,'Что недоступно','admin_stats_quality_unavailable',scope)],...pr229Footer(menu,scope)]);}
